import{_ as r,o as t,c as a,a5 as o}from"./chunks/framework.B5tqjWbr.js";const p=JSON.parse('{"title":"学习记录 #0011：三相逆变器控制——UPS输出级的高性能方案","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0011：三相逆变器控制——UPS输出级的高性能方案","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第11课 — 三相逆变器控制（Phase 2核心拓扑） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0011-three-phase-inverter.md","filePath":"content/power/archive/old-learning-records/0011-three-phase-inverter.md","lastUpdated":null}'),n={name:"content/power/archive/old-learning-records/0011-three-phase-inverter.md"};function s(i,e,l,d,c,h){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="学习记录-0011-三相逆变器控制——ups输出级的高性能方案" tabindex="-1">学习记录 #0011：三相逆变器控制——UPS输出级的高性能方案 <a class="header-anchor" href="#学习记录-0011-三相逆变器控制——ups输出级的高性能方案" aria-label="Permalink to &quot;学习记录 #0011：三相逆变器控制——UPS输出级的高性能方案&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第11课 — 三相逆变器控制（Phase 2核心拓扑） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>两电平vs三电平</strong>：&lt;30kVA用两电平，&gt;30kVA用NPC三电平</li><li><strong>离网逆变器</strong>：内部振荡器产生θ（非PLL），电压外环+电流内环，Vq_ref=0</li><li><strong>并网逆变器</strong>：PLL跟踪电网θ，电流环直接控制Id/Iq，Id=有功，Iq=无功</li><li><strong>LCL vs LC</strong>：LCL高频衰减-60dB/dec（更优），但谐振峰更尖锐需额外阻尼</li><li><strong>LCL阻尼</strong>：无源Rd（简单有损耗）、有源阻尼（电容电流反馈）、陷波滤波器</li><li><strong>UPS双重身份</strong>：PFC整流器=并网逆变器，输出逆变器=离网逆变器</li><li><strong>不平衡负载</strong>：正负序双dq控制是性能最好的方案</li><li><strong>电机对照</strong>：三相逆变器与FOC使用完全相同的数学工具链，差异在负载特性</li></ol><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] 正负序双dq控制具体怎么实现？</li><li>[ ] LCL有源阻尼的电容电流反馈法怎么设计？</li><li>[ ] 孤岛检测方法有哪些？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第12课：LLC谐振变换器原理与控制</p>',8)])])}const _=r(n,[["render",s]]);export{p as __pageData,_ as default};
